export function retirementEvent(age: number | "" = ""): LifeEvent {
  return {
    id: "retire",
    label: "Retirement",
    type: "Retirement",
    age,
    cost: 0,
    incomeChange: 0,
    expenseChange: -1200,
    zeroIncome: true
  };
}

